const body = $input.first().json.body;

// Filtra apenas mensagens reais de texto (ignora e2e_notification, status, etc)
const isRealMessage = (
  body.event === 'message' &&
  !body.payload.fromMe &&
  body.payload.body &&
  body.payload.body.trim() !== '' &&
  body.payload._data?.type !== 'e2e_notification'
);

if (isRealMessage) {
  return $input.all();
}
return [];

const body = $input.first().json.body;
const payload = body.payload || body;

// REGRA CRITICA: preservar @lid completo para WAHA WEBJS
const fromRaw = payload.from || '';
let phone;
if (fromRaw.includes('@lid')) {
  phone = fromRaw; // ex: 118747406835835@lid
} else {
  phone = fromRaw.replace('@c.us', '').replace('@s.whatsapp.net', '');
}

const message = (payload.body || payload.text || '').trim();
const session = body.session || 'default';
const msgId = payload.id || '';

if (!message || !phone || phone.includes('-') || (payload.fromMe === true)) {
  return [];
}

return [{ json: { phone, message, session, msgId, rawBody: body } }];

const extracted = $input.all()[0]?.json || {};
const sessionRow = $input.all()[1]?.json || null;

const phone = extracted.phone;
const message = extracted.message;
const session = extracted.session;
const nicho = sessionRow?.nicho || null;
const historico = sessionRow?.historico ? JSON.parse(sessionRow.historico) : [];

return [{ json: { phone, message, session, nicho, historico } }];

const phone = $('Extrair Dados WAHA').first().json.phone;
const message = $('Extrair Dados WAHA').first().json.message;
const historico = $('Merge Dados + Sessao').first().json.historico || [];

const mensagens = historico.map(h => ({ role: h.role, content: h.content }));
mensagens.push({ role: 'user', content: message });

return [{ json: { ...$input.first().json, mensagens_formatadas: mensagens } }];

